t.script:
(function () {
    'use strict';

    function ready(fn) {
        if (document.readyState === 'loading') {
            document.addEventListener('DOMContentLoaded', fn);
        } else {
            fn();
        }
    }

    function pinSvg(fill, innerFill) {
        return '<svg xmlns="http://www.w3.org/2000/svg" width="32" height="45" viewBox="0 0 32 45" fill="none"><path d="M16 0C7.17 0 0 7.17 0 16c0 12 16 29 16 29s16-17 16-29C32 7.17 24.83 0 16 0Z" fill="' + fill + '"/><circle cx="16" cy="16" r="5.5" fill="' + innerFill + '"/></svg>';
    }

    const stores = [
        { name: 'Excellent Stores', branch: 'Movie Towne Mall', address: 'MovieTowne Boulevard, Audrey Jeffers Hwy, Port of Spain', lat: 10.6618, lng: -61.5331 },
        { name: 'Excellent Stores', branch: 'Trincity Mall', address: 'Trincity Central Road, Trincity', lat: 10.6263, lng: -61.3544 },
        { name: 'Excellent Stores', branch: 'Gulf City Mall', address: 'Gulf City Mall, La Romaine, San Fernando', lat: 10.2724, lng: -61.4633 },
        { name: 'Excellent Stores', branch: 'C3 Centre', address: 'C3 Centre, Corinth Road, San Fernando', lat: 10.2629, lng: -61.4541 }
    ];

    let map = null;
    let infoWindow = null;
    let markers = [];
    let activeStoreIndex = 0;
    let fallbackIframe = null;

    function googleIframeUrl(lat, lng, zoom) {
        return 'https://www.google.com/maps?q=' + encodeURIComponent(lat + ',' + lng) + '&z=' + (zoom || 10) + '&output=embed';
    }

    function markerIcon(fill) {
        if (!window.google || !google.maps) return null;
        const svg = encodeURIComponent(pinSvg(fill, '#fff6ea'));
        return {
            url: 'data:image/svg+xml;charset=UTF-8,' + svg,
            scaledSize: new google.maps.Size(32, 45),
            anchor: new google.maps.Point(16, 45)
        };
    }

    function renderStoreList(filterText) {
        const list = document.getElementById('ib-store-list');
        if (!list) return;
        const normalized = (filterText || '').toLowerCase().trim();
        const filtered = stores
            .map(function(store, index) { return { store: store, index: index }; })
            .filter(function(item) {
                const haystack = (item.store.name + ' ' + item.store.branch + ' ' + item.store.address).toLowerCase();
                return !normalized || haystack.indexOf(normalized) !== -1;
            });

        if (!filtered.length) {
            list.innerHTML = '<div class="ib-store-card"><span></span><div><h3>No stores found</h3><p>Try another search term.</p></div></div>';
            return;
        }

        list.innerHTML = filtered.map(function(item) {
            const store = item.store;
            const index = item.index;
            const active = index === activeStoreIndex ? ' is-active' : '';
            const pinFill = index === activeStoreIndex ? '#fff6ea' : '#f05c40';
            const pinInner = index === activeStoreIndex ? '#f05c40' : '#fff6ea';
            return '<button type="button" class="ib-store-card' + active + '" data-store-index="' + index + '">' +
                    '<span class="ib-store-pin">' + pinSvg(pinFill, pinInner) + '</span>' +
                    '<span><h3>' + store.name + '<br/>' + store.branch + '</h3><p>' + store.address + '</p></span>' +
                '</button>';
        }).join('');

        list.querySelectorAll('[data-store-index]').forEach(function(button) {
            button.addEventListener('click', function() {
                const index = parseInt(this.getAttribute('data-store-index'), 10);
                selectStore(index, true);
            });
        });
    }

    function storeInfoHtml(store) {
        return '<div style="background:#f05c40;color:#fff6ea;padding:18px 22px;max-width:260px;font-family:Afacad,Arial,sans-serif;">' +
            '<strong style="font-size:18px;line-height:1.02;display:block;margin-bottom:7px;">' + store.name + '<br/>' + store.branch + '</strong>' +
            '<span style="font-size:14px;line-height:1.15;display:block;">' + store.address + '</span>' +
        '</div>';
    }

    function selectStore(index, shouldRenderList) {
        const store = stores[index];
        if (!store) return;
        activeStoreIndex = index;

        if (map && markers[index]) {
            map.panTo({ lat: store.lat, lng: store.lng });
            map.setZoom(13);
            infoWindow.setContent(storeInfoHtml(store));
            infoWindow.open({ anchor: markers[index], map: map });
        } else if (fallbackIframe) {
            fallbackIframe.src = googleIframeUrl(store.lat, store.lng, 13);
        }

        if (shouldRenderList) {
            const search = document.getElementById('ib-store-search');
            renderStoreList(search ? search.value : '');
        }
    }

    function initIframeFallback(mapEl) {
        mapEl.innerHTML = '<iframe title="Island Borne Google Map" loading="lazy" allowfullscreen referrerpolicy="no-referrer-when-downgrade" src="' + googleIframeUrl(stores[0].lat, stores[0].lng, 10) + '"></iframe>' +
            '<div class="ib-map-fallback-notice">Add your Google Maps API key in the module to enable custom markers and list-to-map popups.</div>';
        fallbackIframe = mapEl.querySelector('iframe');
    }

    window.ibInitGoogleMap = function () {
        const mapEl = document.getElementById('ib-google-map');
        if (!mapEl || !window.google || !google.maps) return;

        map = new google.maps.Map(mapEl, {
            center: { lat: 10.5364, lng: -61.3119 },
            zoom: 9,
            mapTypeControl: false,
            streetViewControl: false,
            fullscreenControl: true,
            zoomControl: true,
            styles: [
                { elementType: 'geometry', stylers: [{ color: '#ece5dc' }] },
                { elementType: 'labels.text.fill', stylers: [{ color: '#5e5a55' }] },
                { elementType: 'labels.text.stroke', stylers: [{ color: '#fff6ea' }] },
                { featureType: 'poi', stylers: [{ visibility: 'off' }] },
                { featureType: 'road', elementType: 'geometry', stylers: [{ color: '#ffffff' }] },
                { featureType: 'road', elementType: 'geometry.stroke', stylers: [{ color: '#d5c9bf' }] },
                { featureType: 'water', elementType: 'geometry', stylers: [{ color: '#8bd3de' }] }
            ]
        });

        infoWindow = new google.maps.InfoWindow({ pixelOffset: new google.maps.Size(0, -4) });
        markers = stores.map(function(store, index) {
            const marker = new google.maps.Marker({
                position: { lat: store.lat, lng: store.lng },
                map: map,
                title: store.name + ' ' + store.branch,
                icon: markerIcon('#f05c40')
            });
            marker.addListener('click', function () { selectStore(index, true); });
            return marker;
        });
        selectStore(0, true);
    };

    function loadGoogleMap(section, mapEl) {
        const key = (section.getAttribute('data-google-key') || '').trim();
        const hasUsableKey = key && key.indexOf('PASTE_GOOGLE_MAPS_API_KEY_HERE') === -1 && key.length > 20;

        if (!hasUsableKey) {
            initIframeFallback(mapEl);
            return;
        }

        if (window.google && google.maps) {
            window.ibInitGoogleMap();
            return;
        }

        const script = document.createElement('script');
        script.src = 'https://maps.googleapis.com/maps/api/js?key=' + encodeURIComponent(key) + '&callback=ibInitGoogleMap';
        script.async = true;
        script.defer = true;
        script.onerror = function () { initIframeFallback(mapEl); };
        document.head.appendChild(script);
    }

    function startStoreFinder() {
        const section = document.querySelector('.ib-store-section');
        const mapEl = document.getElementById('ib-google-map');
        const search = document.getElementById('ib-store-search');
        const searchButton = document.getElementById('ib-store-search-button');

        renderStoreList('');
        if (section && mapEl) loadGoogleMap(section, mapEl);

        if (search) {
            search.addEventListener('input', function () { renderStoreList(this.value); });
            search.addEventListener('keydown', function (event) {
                if (event.key === 'Enter') {
                    event.preventDefault();
                    const first = document.querySelector('#ib-store-list [data-store-index]');
                    if (first) first.click();
                }
            });
        }

        if (searchButton) {
            searchButton.addEventListener('click', function () {
                const first = document.querySelector('#ib-store-list [data-store-index]');
                if (first) first.click();
            });
        }
    }

    function startMobileMenu() {
        const page = document.querySelector('.ib-page');
        const btn = document.getElementById('ib-mobile-menu-button');
        const nav = document.getElementById('ib-nav');
        if (!page || !btn || !nav) return;

        btn.addEventListener('click', function () {
            const open = page.classList.toggle('is-mobile-menu-open');
            btn.setAttribute('aria-expanded', open ? 'true' : 'false');
        });

        nav.querySelectorAll('a').forEach(function (link) {
            link.addEventListener('click', function () {
                page.classList.remove('is-mobile-menu-open');
                btn.setAttribute('aria-expanded', 'false');
            });
        });
    }

    function startHeroSlideshow() {
        const hero = document.querySelector('[data-ib-slideshow]');
        if (!hero) return;
        const slides = hero.querySelectorAll('.ib-hero-slide');
        if (slides.length <= 1) return;
        let index = 0;
        setInterval(function () {
            slides[index].classList.remove('is-active');
            index = (index + 1) % slides.length;
            slides[index].classList.add('is-active');
        }, 5200);
    }

    ready(function () {
        try { document.body.classList.add('ib-island-page'); } catch (e) {}
        startMobileMenu();
        startHeroSlideshow();
        startStoreFinder();
    });
})();
